def get_connection():
    """
    Reads connection details from environment variables (or .env file).
    Falls back to sensible localhost defaults so you can run with zero config
    on a local dev Postgres instance.
    """
    host     = os.getenv("DB_HOST",     "localhost")
    port     = os.getenv("DB_PORT",     "5432")
    dbname   = os.getenv("DB_NAME",     "monike")
    user     = os.getenv("DB_USER",     "postgres")
    password = os.getenv("DB_PASSWORD", "")

    try:
        conn = psycopg2.connect(
            host=host, port=port, dbname=dbname,
            user=user, password=password,
            connect_timeout=10,
        )
        return conn
    except psycopg2.OperationalError as e:
        print(f"\n  ERROR: Could not connect to Postgres.\n  {e}")
        print(
            f"\n  Check your .env file or environment variables:\n"
            f"    DB_HOST={host}\n"
            f"    DB_PORT={port}\n"
            f"    DB_NAME={dbname}\n"
            f"    DB_USER={user}\n"
            f"    DB_PASSWORD=***\n"
        )
        sys.exit(1)


