#  DATA LOADING HELPERS
# ══════════════════════════════════════════════════════════════════════════════

def decode_transactions() -> pd.DataFrame:
    """
    Decode TRANSACTIONS_B64 → DataFrame.
    Tolerates the blob being truncated in this template (we pad with '=' 
    and ignore padding errors gracefully).
    """
    raw = TRANSACTIONS_B64.strip()
    # Add padding in case the string was trimmed
    raw += "=" * (4 - len(raw) % 4)
    try:
        decoded = base64.b64decode(raw).decode("utf-8")
    except Exception as e:
        print(f"  WARN: Could not decode TRANSACTIONS_B64 — {e}")
        print("  Make sure you pasted the full string from spending_analyzer.py")
        return pd.DataFrame()

    df = pd.read_csv(io.StringIO(decoded), parse_dates=["Trans_Date"])
    df.columns = [c.strip() for c in df.columns]
    df["Debit"]  = pd.to_numeric(df.get("Debit",  0), errors="coerce").fillna(0)
    df["Credit"] = pd.to_numeric(df.get("Credit", 0), errors="coerce").fillna(0)
    return df


def decode_daily() -> pd.DataFrame:
    """Decode DAILY_B64 → DataFrame."""
    raw = DAILY_B64.strip()
    raw += "=" * (4 - len(raw) % 4)
    try:
        decoded = base64.b64decode(raw).decode("utf-8")
    except Exception as e:
        print(f"  WARN: Could not decode DAILY_B64 — {e}")
        return pd.DataFrame()

    df = pd.read_csv(io.StringIO(decoded), parse_dates=["date"])
    # Coerce every numeric column
    numeric_cols = [
        "total_debit", "total_credit", "num_transactions", "max_single",
        "p2p_spend", "pos_spend", "data_spend", "savings_out", "online_spend",
        "family_spend", "airtime_spend", "discretionary",
        "rolling_7d_avg", "rolling_14d_avg", "prev_day_spend",
        "prev_week_same_day", "dow", "dom", "month", "is_weekend", "high_spend",
    ]
    for col in numeric_cols:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors="coerce").fillna(0)
    return df


def load_csv_log() -> pd.DataFrame:
    """Load the old my_spending_log.csv if it exists."""
    path = Path(DAILY_LOG_FILE)
    if not path.exists():
        return pd.DataFrame()
    df = pd.read_csv(path, parse_dates=["date"])
    print(f"  Found {len(df)} rows in {DAILY_LOG_FILE}")
    return df


