def safe_float(val, default=0.0) -> float:
    try:
        return float(val)
    except (TypeError, ValueError):
        return default


def safe_bool(val) -> bool:
    if isinstance(val, bool):
        return val
    try:
        return bool(int(val))
    except (TypeError, ValueError):
        return False


def insert_transactions(conn, df: pd.DataFrame) -> int:
    """
    Bulk-insert all rows into the transactions table.
    Uses ON CONFLICT DO NOTHING on (trans_date, description, debit, credit)
    so re-running the script is safe.
    """
    if df.empty:
        print("  SKIP: transactions DataFrame is empty.")
        return 0

    # Build a unique constraint key (Postgres doesn't have one on the raw table,
    # but we guard with a temp dedupe key string for the upsert logic below).
    rows = []
    for _, r in df.iterrows():
        rows.append((
            r["Trans_Date"].to_pydatetime() if hasattr(r["Trans_Date"], "to_pydatetime") else r["Trans_Date"],
            str(r.get("Description", ""))[:2000],
            str(r.get("Category",    "Other"))[:60],
            safe_float(r.get("Debit",  0)),
            safe_float(r.get("Credit", 0)),
        ))

    sql = """
        INSERT INTO transactions (trans_date, description, category, debit, credit)
        VALUES %s
        ON CONFLICT DO NOTHING
    """
    with conn.cursor() as cur:
        execute_values(cur, sql, rows, page_size=500)
    conn.commit()
    return len(rows)


def insert_daily_features(conn, df: pd.DataFrame) -> int:
    """
    Bulk-insert the pre-computed daily feature matrix.
    ON CONFLICT (date) DO UPDATE keeps the latest values if you re-run.
    """
    if df.empty:
        print("  SKIP: daily features DataFrame is empty.")
        return 0

    rows = []
    for _, r in df.iterrows():
        rows.append((
            r["date"].date() if hasattr(r["date"], "date") else r["date"],
            safe_float(r.get("total_debit")),
            safe_float(r.get("total_credit")),
            int(safe_float(r.get("num_transactions"))),
            safe_float(r.get("max_single")),
            safe_float(r.get("p2p_spend")),
            safe_float(r.get("pos_spend")),
            safe_float(r.get("data_spend")),
            safe_float(r.get("savings_out")),
            safe_float(r.get("online_spend")),
            safe_float(r.get("family_spend")),
            safe_float(r.get("airtime_spend")),
            safe_float(r.get("discretionary")),
            int(safe_float(r.get("dow",         0))),
            int(safe_float(r.get("dom",         1))),
            int(safe_float(r.get("month",       1))),
            safe_bool(r.get("is_weekend",       0)),
            safe_float(r.get("rolling_7d_avg")),
            safe_float(r.get("rolling_14d_avg")),
            safe_float(r.get("prev_day_spend")),
            safe_float(r.get("prev_week_same_day")),
            safe_bool(r.get("high_spend",       0)),
        ))

    sql = """
        INSERT INTO daily_features (
            date,
            total_debit, total_credit, num_transactions, max_single,
            p2p_spend, pos_spend, data_spend, savings_out,
            online_spend, family_spend, airtime_spend, discretionary,
            dow, dom, month, is_weekend,
            rolling_7d_avg, rolling_14d_avg, prev_day_spend, prev_week_same_day,
            high_spend
        )
        VALUES %s
        ON CONFLICT (date) DO UPDATE SET
            total_debit         = EXCLUDED.total_debit,
            total_credit        = EXCLUDED.total_credit,
            num_transactions    = EXCLUDED.num_transactions,
            max_single          = EXCLUDED.max_single,
            p2p_spend           = EXCLUDED.p2p_spend,
            pos_spend           = EXCLUDED.pos_spend,
            data_spend          = EXCLUDED.data_spend,
            savings_out         = EXCLUDED.savings_out,
            online_spend        = EXCLUDED.online_spend,
            family_spend        = EXCLUDED.family_spend,
            airtime_spend       = EXCLUDED.airtime_spend,
            discretionary       = EXCLUDED.discretionary,
            dow                 = EXCLUDED.dow,
            dom                 = EXCLUDED.dom,
            month               = EXCLUDED.month,
            is_weekend          = EXCLUDED.is_weekend,
            rolling_7d_avg      = EXCLUDED.rolling_7d_avg,
            rolling_14d_avg     = EXCLUDED.rolling_14d_avg,
            prev_day_spend      = EXCLUDED.prev_day_spend,
            prev_week_same_day  = EXCLUDED.prev_week_same_day,
            high_spend          = EXCLUDED.high_spend
    """
    with conn.cursor() as cur:
        execute_values(cur, sql, rows, page_size=200)
    conn.commit()
    return len(rows)


def insert_daily_log(conn, df: pd.DataFrame) -> int:
    """Import the old CSV log into the daily_log table."""
    if df.empty:
        return 0

    rows = []
    for _, r in df.iterrows():
        rows.append((
            r["date"].date() if hasattr(r["date"], "date") else r["date"],
            safe_float(r.get("total_debit")),
            safe_float(r.get("total_credit")),
            int(safe_float(r.get("num_transactions"))),
            safe_float(r.get("max_single")),
            safe_float(r.get("p2p_spend")),
            safe_float(r.get("pos_spend")),
            safe_float(r.get("data_spend")),
            safe_float(r.get("savings_out")),
            safe_float(r.get("online_spend")),
            safe_float(r.get("family_spend")),
            safe_float(r.get("airtime_spend")),
            safe_float(r.get("discretionary")),
            int(safe_float(r.get("dow",          0))),
            int(safe_float(r.get("dom",          1))),
            int(safe_float(r.get("month",        1))),
            safe_bool(r.get("is_weekend",        0)),
            safe_float(r.get("rolling_7d_avg")),
            safe_float(r.get("rolling_14d_avg")),
            safe_float(r.get("prev_day_spend")),
            safe_float(r.get("prev_week_same_day")),
            safe_bool(r.get("high_spend",        0)),
            "csv_import",
        ))

    sql = """
        INSERT INTO daily_log (
            date,
            total_debit, total_credit, num_transactions, max_single,
            p2p_spend, pos_spend, data_spend, savings_out,
            online_spend, family_spend, airtime_spend, discretionary,
            dow, dom, month, is_weekend,
            rolling_7d_avg, rolling_14d_avg, prev_day_spend, prev_week_same_day,
            high_spend, source
        )
        VALUES %s
        ON CONFLICT (date) DO UPDATE SET
            total_debit      = EXCLUDED.total_debit,
            total_credit     = EXCLUDED.total_credit,
            high_spend       = EXCLUDED.high_spend,
            source           = EXCLUDED.source,
            updated_at       = NOW()
    """
    with conn.cursor() as cur:
        execute_values(cur, sql, rows, page_size=200)
    conn.commit()
    return len(rows)


