#  SCHEMA RESET
# ══════════════════════════════════════════════════════════════════════════════

def drop_all_tables(conn):
    """Drop everything so you can start fresh. Use with caution."""
    with conn.cursor() as cur:
        cur.execute("DROP VIEW  IF EXISTS all_daily CASCADE;")
        cur.execute("DROP TABLE IF EXISTS daily_log       CASCADE;")
        cur.execute("DROP TABLE IF EXISTS daily_features  CASCADE;")
        cur.execute("DROP TABLE IF EXISTS transactions    CASCADE;")
    conn.commit()
    print("  ✔  All tables and views dropped.")


# ══════════════════════════════════════════════════════════════════════════════
#  VERIFICATION
# ══════════════════════════════════════════════════════════════════════════════

def verify(conn):
    """Print row counts for every table and a sample sanity check."""
    queries = {
        "transactions":   "SELECT COUNT(*) FROM transactions",
        "daily_features": "SELECT COUNT(*) FROM daily_features",
        "daily_log":      "SELECT COUNT(*) FROM daily_log",
        "all_daily view": "SELECT COUNT(*) FROM all_daily",
    }

    print("\n  ┌─────────────────────────────┬───────────────┐")
    print("  │ Table / View                │   Row Count   │")
    print("  ├─────────────────────────────┼───────────────┤")
    with conn.cursor() as cur:
        for label, sql in queries.items():
            try:
                cur.execute(sql)
                count = cur.fetchone()[0]
                print(f"  │ {label:<27} │ {count:>13,} │")
            except Exception as e:
                print(f"  │ {label:<27} │ {'ERROR':>13} │  ({e})")
    print("  └─────────────────────────────┴───────────────┘")

    # Quick sanity: total debit across all transactions should be > 0
    with conn.cursor() as cur:
        cur.execute("SELECT COALESCE(SUM(debit), 0) FROM transactions WHERE debit > 0")
        total = cur.fetchone()[0]
        if total > 0:
            print(f"\n  ✔  Total debits in transactions table: ₦{total:,.2f}")
        else:
            print("\n  ⚠  Total debits = 0. The transactions table may be empty.")

    # Check date range in daily_features
    with conn.cursor() as cur:
        try:
            cur.execute("SELECT MIN(date), MAX(date), COUNT(*) FROM daily_features")
            row = cur.fetchone()
            if row and row[2]:
                print(f"  ✔  daily_features spans {row[0]} → {row[1]}  ({row[2]} days)")
        except Exception:
            pass


# ══════════════════════════════════════════════════════════════════════════════
#  RECOMPUTE ROLLING FEATURES (post-insert)
# ══════════════════════════════════════════════════════════════════════════════

ROLLING_SQL = """
-- Recompute all rolling / lag features in-place using window functions.
-- Run this after any bulk insert or manual log entry.
WITH ordered AS (
    SELECT
        id, date, total_debit,
        AVG(total_debit) OVER (
            ORDER BY date
            ROWS BETWEEN 6 PRECEDING AND CURRENT ROW
        )                                                          AS r7,
        AVG(total_debit) OVER (
            ORDER BY date
            ROWS BETWEEN 13 PRECEDING AND CURRENT ROW
        )                                                          AS r14,
        LAG(total_debit, 1, 0) OVER (ORDER BY date)               AS prev_day,
        LAG(total_debit, 7, 0) OVER (ORDER BY date)               AS prev_week
    FROM daily_features
)
UPDATE daily_features df
SET
    rolling_7d_avg      = ROUND(ordered.r7::NUMERIC,    2),
    rolling_14d_avg     = ROUND(ordered.r14::NUMERIC,   2),
    prev_day_spend      = ROUND(ordered.prev_day::NUMERIC, 2),
    prev_week_same_day  = ROUND(ordered.prev_week::NUMERIC, 2)
FROM ordered
WHERE df.id = ordered.id;
"""

def recompute_rolling(conn):
    """Update rolling averages and lag columns after inserting all rows."""
    with conn.cursor() as cur:
        cur.execute(ROLLING_SQL)
    conn.commit()
    print("  ✔  Rolling averages and lag features recomputed.")


